import React from 'react';
import { useAuth } from '../../context/AuthContext';
import Button from '../../components/common/Button';
import './LoginPage.css';

const LoginPage = () => {
  const { login } = useAuth();

  return (
    <div className="login-page">
      <div className="login-card">
        <div className="login-logo">
          <span className="login-logo-icon">⛓</span>
          <h1 className="login-logo-text">Chain</h1>
          <p className="login-logo-sub">HR Management Platform</p>
        </div>

        <div className="login-divider" />

        <div className="login-body">
          <h2 className="login-title">Bun venit!</h2>
          <p className="login-description">
            Autentifică-te cu contul tău pentru a accesa platforma de management HR.
          </p>
          <Button variant="primary" size="lg" fullWidth onClick={() => login()}>
            🔐 Autentificare cu Auth0
          </Button>
        </div>

        <div className="login-features">
          {[
            { icon: '⏱', text: 'Pontaj digital în timp real' },
            { icon: '🏖', text: 'Gestionare concedii simplificate' },
            { icon: '💰', text: 'Calcul automat salariu' },
            { icon: '🤖', text: 'Asistent AI integrat' },
          ].map((f) => (
            <div key={f.text} className="login-feature-item">
              <span>{f.icon}</span>
              <span>{f.text}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="login-bg" />
    </div>
  );
};

export default LoginPage;
